    14→
    15→	"github.com/cilium/cilium/pkg/datapath/linux/bandwidth"
    16→	datapath "github.com/cilium/cilium/pkg/datapath/types"
    17→	"github.com/cilium/cilium/pkg/eventqueue"
    18→	"github.com/cilium/cilium/pkg/logging/logfields"
